import React, { useState, useEffect } from 'react';

const TRANSLATIONS = {
  "en-US": {
    "appTitle": "🏛️ Historical SVG amphitheater",
    "appDescription": "Enter a historical event to witness pivotal moments in SVG format!",
    "eventPlaceholder": "Enter historical event...",
    "beginButton": "Begin the chronicle!",
    "loadingText": "Recreating moment",
    "of": "of",
    "returnButton": "Return",
    "suggestedEventsTitle": "Notable events to explore:",
    "worldWarII": "World War II",
    "ancientEgypt": "Ancient Egypt",
    "moonLanding": "Moon Landing",
    "errorGenerateScenes": "Failed to generate scenes for this historical event. Please try another one.",
    "errorGenerateScenesGeneral": "Failed to generate scenes. Please try again.",
    "errorPrefix": "Error generating scenes: ",
    "claudePromptScenes": "List 5 of the most pivotal, iconic moments from the historical event",
    "claudePromptSVG": "Create an iconic SVG representation of this pivotal moment from the historical event"
  },
  /* LOCALE_PLACEHOLDER_START */
  "es-ES": {
    "appTitle": "🏛️ Anfiteatro SVG histórico",
    "appDescription": "¡Ingresa un evento histórico para presenciar momentos cruciales en formato SVG!",
    "eventPlaceholder": "Ingresa evento histórico...",
    "beginButton": "¡Comenzar la crónica!",
    "loadingText": "Recreando momento",
    "of": "de",
    "returnButton": "Regresar",
    "suggestedEventsTitle": "Eventos notables para explorar:",
    "worldWarII": "Segunda Guerra Mundial",
    "ancientEgypt": "Antiguo Egipto",
    "moonLanding": "Alunizaje",
    "errorGenerateScenes": "No se pudieron generar escenas para este evento histórico. Por favor, prueba con otro.",
    "errorGenerateScenesGeneral": "No se pudieron generar escenas. Por favor, inténtalo de nuevo.",
    "errorPrefix": "Error generando escenas: ",
    "claudePromptScenes": "Lista 5 de los momentos más cruciales e icónicos del evento histórico",
    "claudePromptSVG": "Crea una representación SVG icónica de este momento crucial del evento histórico"
  }
  /* LOCALE_PLACEHOLDER_END */
};

const appLocale = '{{APP_LOCALE}}';
const browserLocale = navigator.languages?.[0] || navigator.language || 'en-US';
const findMatchingLocale = (locale) => {
  if (TRANSLATIONS[locale]) return locale;
  const lang = locale.split('-')[0];
  const match = Object.keys(TRANSLATIONS).find(key => key.startsWith(lang + '-'));
  return match || 'en-US';
};
const locale = (appLocale !== '{{APP_LOCALE}}') ? findMatchingLocale(appLocale) : findMatchingLocale(browserLocale);
const t = (key) => TRANSLATIONS[locale]?.[key] || TRANSLATIONS['en-US'][key] || key;

const HistoricalTheater = () => {
  const [eventTitle, setEventTitle] = useState('');
  const [loading, setLoading] = useState(false);
  const [scenes, setScenes] = useState([]);
  const [currentScene, setCurrentScene] = useState(0);
  const [showScenes, setShowScenes] = useState(false);
  const [error, setError] = useState('');
  const [loadingProgress, setLoadingProgress] = useState({ current: 0, total: 0 });

  const generateHistoricalScenes = async (eventTitle) => {
    const prompt = `${t('claudePromptScenes')} "${eventTitle}". For each moment, provide a brief description that captures its essence and visual impact.

REQUIREMENTS:
- Focus on the most significant and memorable moments
- Scenes should be historically accurate and visually striking
- Each description should be 5-10 words
- Format as a simple numbered list

Example format:
1. Scene description
2. Scene description
3. Scene description
4. Scene description
5. Scene description

Please respond in ${locale} language`;

    try {
      const response = await window.claude.complete(prompt);
      // Extract scene descriptions from the response
      const scenes = response.split('\n')
        .filter(line => line.match(/^\d+\./))
        .map(line => line.replace(/^\d+\.\s*/, '').trim())
        .slice(0, 5);

      return scenes.length === 5 ? scenes : null;
    } catch (error) {
      console.error('Error generating scenes:', error);
      return null;
    }
  };

  const createSVGPrompt = (eventTitle, sceneDescription) => {
    return `${t('claudePromptSVG')} "${eventTitle}":

Scene: ${sceneDescription}

REQUIREMENTS:
1. The SVG must fill the screen - use viewBox="0 0 600 400" preserveAspectRatio="none" width="100%" height="100%"
2. Use a dramatic, classical art style reminiscent of historical paintings and engravings
3. Capture the ESSENCE of the moment - make it historically recognizable and impactful
4. Use a period-appropriate color palette (earth tones, classical colors) for maximum historical authenticity
5. Focus on the most significant visual elements of the historical moment
6. Include key historical figures in distinguishable poses/positions
7. Make it feel like a classical painting or historical illustration - dramatic, dignified, and iconic
8. Use SVG paths, shapes, and gradients to create depth and classical atmosphere
9. Ensure all elements are properly contained within the 600x400 viewport
10. Make the scene immediately recognizable as this historical moment

Style inspiration: Think classical paintings, historical engravings, museum illustrations, dramatic historical art

Please respond in ${locale} language

Respond with ONLY the complete SVG code, no explanations or additional text.`;
  };

  const generateScenes = async () => {
    if (!eventTitle.trim()) return;

    setLoading(true);
    setError('');
    setScenes([]);
    setCurrentScene(0);
    setLoadingProgress({ current: 0, total: 0 });

    try {
      // First, generate scene descriptions for the historical event
      const historicalScenes = await generateHistoricalScenes(eventTitle);

      if (!historicalScenes) {
        setError(t('errorGenerateScenes'));
        setLoading(false);
        return;
      }

      const generatedScenes = [];

      setLoadingProgress({ current: 0, total: historicalScenes.length });

      for (let i = 0; i < historicalScenes.length; i++) {
        setLoadingProgress({ current: i + 1, total: historicalScenes.length });
        const prompt = createSVGPrompt(eventTitle, historicalScenes[i]);

        try {
          const response = await window.claude.complete(prompt);

          // Extract just the SVG code from the response
          const svgMatch = response.match(/<svg[\s\S]*?<\/svg>/i);
          if (svgMatch) {
            generatedScenes.push({
              svg: svgMatch[0],
              description: historicalScenes[i]
            });
          } else {
            console.error('No SVG found in response for scene:', historicalScenes[i]);
          }
        } catch (sceneError) {
          console.error('Error generating scene:', sceneError);
        }
      }

      if (generatedScenes.length > 0) {
        setScenes(generatedScenes);
        setShowScenes(true);
      } else {
        setError(t('errorGenerateScenesGeneral'));
      }
    } catch (err) {
      setError(t('errorPrefix') + err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (showScenes && scenes.length > 0) {
      const interval = setInterval(() => {
        setCurrentScene((prev) => (prev + 1) % scenes.length);
      }, 8000); // Change scene every 8 seconds

      return () => clearInterval(interval);
    }
  }, [showScenes, scenes.length]);

  return (
    <div className="min-h-screen bg-gradient-to-b from-stone-200 to-stone-300 text-amber-900 relative overflow-hidden">
      {/* Classical Amphitheater Background */}
      <div className="absolute inset-0">
        {/* Sky/Backdrop */}
        <div className="absolute top-0 left-0 w-full h-1/3 bg-gradient-to-b from-blue-200 to-blue-100" />

        {/* Amphitheater Bowl Structure */}
        <div className="absolute bottom-0 left-0 w-full h-2/3 bg-gradient-to-t from-stone-400 to-stone-300" />

        {/* Classical Columns - Fixed z-index */}
        <div className="absolute left-8 top-16 w-16 h-96">
          {/* Column Shaft */}
          <div className="relative w-16 h-96 bg-gradient-to-r from-stone-200 via-stone-100 to-stone-200 shadow-lg">
            {/* Vertical fluting - multiple channels */}
            <div className="absolute top-6 bottom-3 left-1 w-2 bg-gradient-to-r from-stone-300 to-stone-200 opacity-70" />
            <div className="absolute top-6 bottom-3 left-4 w-2 bg-gradient-to-r from-stone-300 to-stone-200 opacity-70" />
            <div className="absolute top-6 bottom-3 left-7 w-2 bg-gradient-to-r from-stone-300 to-stone-200 opacity-70" />
            <div className="absolute top-6 bottom-3 left-10 w-2 bg-gradient-to-r from-stone-300 to-stone-200 opacity-70" />
            <div className="absolute top-6 bottom-3 left-13 w-2 bg-gradient-to-r from-stone-300 to-stone-200 opacity-70" />
          </div>

          {/* Column Capital (wider top) - Higher z-index */}
          <div className="absolute -top-6 -left-4 w-24 h-12 bg-gradient-to-b from-stone-100 to-stone-200 rounded-sm shadow-lg border-b-2 border-stone-300 z-10" />

          {/* Column Base */}
          <div className="absolute -bottom-3 -left-2 w-20 h-6 bg-gradient-to-t from-stone-300 to-stone-200 rounded-sm shadow-md z-10" />
        </div>

        <div className="absolute right-8 top-16 w-16 h-96">
          {/* Column Shaft */}
          <div className="relative w-16 h-96 bg-gradient-to-l from-stone-200 via-stone-100 to-stone-200 shadow-lg">
            {/* Vertical fluting - multiple channels */}
            <div className="absolute top-6 bottom-3 right-1 w-2 bg-gradient-to-l from-stone-300 to-stone-200 opacity-70" />
            <div className="absolute top-6 bottom-3 right-4 w-2 bg-gradient-to-l from-stone-300 to-stone-200 opacity-70" />
            <div className="absolute top-6 bottom-3 right-7 w-2 bg-gradient-to-l from-stone-300 to-stone-200 opacity-70" />
            <div className="absolute top-6 bottom-3 right-10 w-2 bg-gradient-to-l from-stone-300 to-stone-200 opacity-70" />
            <div className="absolute top-6 bottom-3 right-13 w-2 bg-gradient-to-l from-stone-300 to-stone-200 opacity-70" />
          </div>

          {/* Column Capital (wider top) - Higher z-index */}
          <div className="absolute -top-6 -right-4 w-24 h-12 bg-gradient-to-b from-stone-100 to-stone-200 rounded-sm shadow-lg border-b-2 border-stone-300 z-10" />

          {/* Column Base */}
          <div className="absolute -bottom-3 -right-2 w-20 h-6 bg-gradient-to-t from-stone-300 to-stone-200 rounded-sm shadow-md z-10" />
        </div>

        {/* Stage/Orchestra Area - REMOVED */}
      </div>

      {/* Classical Amphitheater Stage Frame */}
      <div className="relative z-10 max-w-4xl mx-auto pt-20 px-8">
        <div className="relative">
          {/* Elevated Stage Platform */}
          <div className="bg-gradient-to-b from-stone-200 to-stone-300 p-8 rounded-lg shadow-2xl border-4 border-stone-400">
            {/* Stage Floor */}
            <div className="bg-gradient-to-b from-gray-50 to-gray-100 rounded border-4 border-stone-500 p-4 shadow-inner">
              {/* Performance Area */}
              <div className="relative bg-parchment rounded overflow-hidden flex items-center justify-center border-2 border-gray-400 shadow-lg" style={{ width: '100%', height: '450px', backgroundColor: '#f5f5f5' }}>
                {!showScenes ? (
                  <div className="text-center max-w-md">
                    <h1 className="text-3xl font-bold mb-8 text-gray-700">
                      {t('appTitle')}
                    </h1>
                    <p className="text-gray-600 mb-8 whitespace-nowrap">
                      {t('appDescription')}
                    </p>
                    <div className="space-y-4">
                      <input
                        type="text"
                        value={eventTitle}
                        onChange={(e) => setEventTitle(e.target.value)}
                        placeholder={t('eventPlaceholder')}
                        className="w-full px-4 py-3 bg-gray-50 border-2 border-gray-300 rounded-lg text-gray-800 placeholder-gray-500 focus:outline-none focus:border-gray-600"
                        onKeyPress={(e) => e.key === 'Enter' && generateScenes()}
                      />
                      <button
                        onClick={generateScenes}
                        disabled={loading}
                        className={`w-full px-6 py-3 ${loading ? 'bg-gray-400' : 'bg-gray-600 hover:bg-gray-700'} disabled:bg-gray-800 text-white font-semibold rounded-lg transition-colors flex items-center justify-center gap-2`}
                      >
                        {loading && (
                          <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" />
                        )}
                        {loading 
                          ? `${t('loadingText')} ${loadingProgress.current} ${t('of')} ${loadingProgress.total}...` 
                          : t('beginButton')
                        }
                      </button>
                      {error && (
                        <p className="text-red-600 text-sm mt-2">{error}</p>
                      )}

                      {/* Suggested Historical Events */}
                      <div className="mt-8 pt-6 border-t border-gray-300">
                        <p className="text-sm text-gray-500 mb-3">{t('suggestedEventsTitle')}</p>
                        <div className="flex flex-wrap gap-2 justify-center">
                          {[
                            { key: 'worldWarII', value: t('worldWarII') },
                            { key: 'ancientEgypt', value: t('ancientEgypt') },
                            { key: 'moonLanding', value: t('moonLanding') }
                          ].map((event) => (
                            <button
                              key={event.key}
                              onClick={() => setEventTitle(event.value)}
                              className="px-3 py-1 text-sm bg-gray-200 hover:bg-gray-300 text-gray-700 rounded-full transition-colors border border-gray-400"
                            >
                              {event.value}
                            </button>
                          ))}
                        </div>
                      </div>
                    </div>
                  </div>
                ) : (
                  <div className="relative w-full h-full">
                    {scenes.length > 0 && scenes[currentScene] && (
                      <div 
                        dangerouslySetInnerHTML={{ 
                          __html: scenes[currentScene].svg.replace(
                            /<svg([^>]*?)>/i,
                            '<svg$1 style="width: 100%; height: 100%; display: block;">'
                          )
                        }}
                        className="w-full h-full absolute inset-0"
                      />
                    )}

                    {/* Scene Navigation */}
                    <div className="absolute bottom-4 left-1/2 transform -translate-x-1/2 flex space-x-2">
                      {scenes.map((_, index) => (
                        <button
                          key={index}
                          onClick={() => setCurrentScene(index)}
                          className={`w-3 h-3 rounded-full transition-all ${
                            index === currentScene ? 'bg-gray-600 scale-125' : 'bg-gray-400'
                          }`}
                        />
                      ))}
                    </div>

                    {/* Scene Title - Smaller and Top Left */}
                    <div className="absolute top-4 left-4 bg-black bg-opacity-60 p-3 rounded max-w-sm">
                      <h2 className="text-sm font-semibold text-gray-200">
                        {eventTitle}
                      </h2>
                      <p className="text-xs text-gray-300 mt-1">
                        {scenes[currentScene]?.description}
                      </p>
                    </div>

                    {/* Back Button */}
                    <button
                      onClick={() => setShowScenes(false)}
                      className="absolute top-4 right-4 px-4 py-2 bg-gray-700 hover:bg-gray-800 text-white rounded-lg text-sm"
                    >
                      {t('returnButton')}
                    </button>
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* Stage Reflection/Shadow - REMOVED */}
        </div>
      </div>

      {/* Curved Amphitheater Seating */}
      <div className="absolute bottom-0 left-0 right-0 h-32 overflow-hidden">
        {/* Back row (highest) */}
        <div className="absolute bottom-24 left-1/2 transform -translate-x-1/2" style={{ width: '800px' }}>
          <div className="flex justify-center space-x-1">
            {Array.from({ length: 25 }).map((_, i) => {
              const angle = (i - 12) * -2; // Negative angle to face inward toward screen
              return (
                <div
                  key={i}
                  className="w-4 h-6 bg-gradient-to-t from-stone-600 to-stone-500 rounded-t"
                  style={{ 
                    transform: `perspective(400px) rotateX(30deg) rotateY(${angle}deg)`,
                    marginLeft: i === 0 ? '0' : '1px'
                  }}
                />
              );
            })}
          </div>
        </div>

        {/* Middle row */}
        <div className="absolute bottom-16 left-1/2 transform -translate-x-1/2" style={{ width: '700px' }}>
          <div className="flex justify-center space-x-1">
            {Array.from({ length: 21 }).map((_, i) => {
              const angle = (i - 10) * -2.5; // Negative angle to face inward
              return (
                <div
                  key={i}
                  className="w-5 h-8 bg-gradient-to-t from-stone-500 to-stone-400 rounded-t"
                  style={{ 
                    transform: `perspective(400px) rotateX(35deg) rotateY(${angle}deg)`,
                    marginLeft: i === 0 ? '0' : '2px'
                  }}
                />
              );
            })}
          </div>
        </div>

        {/* Front row (closest to stage) */}
        <div className="absolute bottom-8 left-1/2 transform -translate-x-1/2" style={{ width: '600px' }}>
          <div className="flex justify-center space-x-2">
            {Array.from({ length: 17 }).map((_, i) => {
              const angle = (i - 8) * -3; // Negative angle to face inward
              return (
                <div
                  key={i}
                  className="w-6 h-10 bg-gradient-to-t from-stone-400 to-stone-300 rounded-t-lg border border-stone-500 hover:scale-110 transition-transform"
                  style={{ 
                    transform: `perspective(400px) rotateX(40deg) rotateY(${angle}deg)`,
                    marginLeft: i === 0 ? '0' : '3px'
                  }}
                />
              );
            })}
          </div>
        </div>

        {/* Curved seating tiers/steps - removed shadows */}
        <div className="absolute bottom-6 left-1/2 transform -translate-x-1/2 w-full max-w-4xl">
          {Array.from({ length: 5 }).map((_, tier) => (
            <div
              key={tier}
              className="absolute w-full bg-stone-300 opacity-20"
              style={{
                height: '2px',
                bottom: `${tier * 8}px`,
                borderRadius: '50%',
                transform: `scaleX(${1 - tier * 0.15})`
              }}
            />
          ))}
        </div>
      </div>

      {/* Classical Lighting */}
      <div className="fixed top-0 left-1/4 w-1/2 h-48 bg-gradient-radial from-amber-200 to-transparent opacity-20 transform rotate-180" />

      {/* Torch Effects - REMOVED */}
    </div>
  );
};

export default HistoricalTheater;
